import json
from datetime import datetime
from typing import Dict, List

# Simulated cloud resource configurations
class CloudSecurityAuditor:
    def __init__(self, account_id: str):
        self.account_id = account_id
        self.findings = []

    def check_s3_bucket_public_access(self, bucket_config: Dict) -> None:
        """Check if S3 bucket has public access enabled - security risk"""
        if bucket_config.get("publicAccessBlock") == False:
            self.findings.append({
                "severity": "HIGH",
                "resource": f"s3://{bucket_config['name']}",
                "issue": "Public access is enabled",
                "recommendation": "Enable S3 Block Public Access"
            })
        else:
            print(f"✓ Bucket {bucket_config['name']}: Public access properly blocked")

    def check_security_group_rules(self, sg_rules: List[Dict]) -> None:
        """Check for overly permissive security group rules"""
        for rule in sg_rules:
            if rule.get("port") == 22 and rule.get("source") == "0.0.0.0/0":
                self.findings.append({
                    "severity": "HIGH",
                    "resource": f"security-group:{rule['sg_id']}",
                    "issue": "SSH open to internet (0.0.0.0/0)",
                    "recommendation": "Restrict SSH access to specific IP ranges"
                })
            elif rule.get("port") == 3389 and rule.get("source") == "0.0.0.0/0":
                self.findings.append({
                    "severity": "HIGH",
                    "resource": f"security-group:{rule['sg_id']}",
                    "issue": "RDP open to internet (0.0.0.0/0)",
                    "recommendation": "Restrict RDP access to specific IP ranges"
                })
            else:
                print(f"✓ Security Group {rule.get('sg_id')}: Port {rule.get('port')} properly restricted")

    def check_iam_password_policy(self, policy: Dict) -> None:
        """Check IAM password policy meets security standards"""
        required_min_length = 12
        requires_uppercase = policy.get("requireUppercaseCharacters", False)
        requires_symbols = policy.get("requireSymbols", False)

        if policy.get("minimumPasswordLength", 0) < required_min_length:
            self.findings.append({
                "severity": "MEDIUM",
                "resource": "IAM Password Policy",
                "issue": f"Password length less than {required_min_length} characters",
                "recommendation": "Increase minimum password length"
            })
        if not requires_uppercase:
            self.findings.append({
                "severity": "MEDIUM",
                "resource": "IAM Password Policy",
                "issue": "Uppercase characters not required",
                "recommendation": "Enable uppercase character requirement"
            })
        if not requires_symbols:
            self.findings.append({
                "severity": "MEDIUM",
                "resource": "IAM Password Policy",
                "issue": "Special characters not required",
                "recommendation": "Enable special character requirement"
            })

    def generate_audit_report(self) -> Dict:
        """Generate security audit report"""
        report = {
            "account_id": self.account_id,
            "audit_date": datetime.now().isoformat(),
            "total_findings": len(self.findings),
            "findings": self.findings
        }
        return report

# Simulated cloud environment scan
auditor = CloudSecurityAuditor("acc-123456789")

# Check S3 buckets
buckets = [
    {"name": "company-public-data", "publicAccessBlock": False},
    {"name": "company-private-data", "publicAccessBlock": True}
]
for bucket in buckets:
    auditor.check_s3_bucket_public_access(bucket)

# Check security groups
security_groups = [
    {"sg_id": "sg-001", "port": 22, "source": "0.0.0.0/0"},
    {"sg_id": "sg-002", "port": 443, "source": "0.0.0.0/0"},
    {"sg_id": "sg-003", "port": 22, "source": "10.0.0.0/8"}
]
for sg in security_groups:
    auditor.check_security_group_rules(sg)

# Check IAM policy
iam_policy = {
    "minimumPasswordLength": 8,
    "requireUppercaseCharacters": False,
    "requireSymbols": True
}
auditor.check_iam_password_policy(iam_policy)

# Generate and print report
report = auditor.generate_audit_report()
print("\n" + "="*50)
print("CLOUD SECURITY AUDIT REPORT")
print("="*50)
print(json.dumps(report, indent=2))
